import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Admin Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"admin/index.md","filePath":"admin/index.md","lastUpdated":1783543014000}'),n={name:"admin/index.md"};function i(s,t,d,l,p,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="admin-documentation" tabindex="-1">Admin Documentation <a class="header-anchor" href="#admin-documentation" aria-label="Permalink to &quot;Admin Documentation&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Documentation in progress</p><p>This page is an early outline. Full admin, operator, and installer documentation is still being written and will be added here. Detailed admin documentation is still available at <a href="https://docs.prokube.ai/" target="_blank" rel="noreferrer">docs.prokube.ai</a>.</p></div><p>Admin documentation covers installation, configuration, user and workspace administration, operations, upgrades, and troubleshooting.</p><p>The future structure should make it clear which parts are shared platform foundation and which parts belong to optional product tracks.</p><h2 id="track-oriented-installation" tabindex="-1">Track-Oriented Installation <a class="header-anchor" href="#track-oriented-installation" aria-label="Permalink to &quot;Track-Oriented Installation&quot;">​</a></h2><p>The installer should eventually support different installation profiles, for example:</p><ul><li>Full platform</li><li>MLOps-focused setup</li><li>AgentOps-focused setup</li><li>Sandbox-focused setup</li></ul><p>The exact scope of these profiles still needs to be defined.</p><h2 id="current-state" tabindex="-1">Current State <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current State&quot;">​</a></h2><p>Detailed admin documentation is still available at <a href="https://docs.prokube.ai/" target="_blank" rel="noreferrer">docs.prokube.ai</a>. New operator and installer documentation will be added here over time.</p><h2 id="available-pages" tabindex="-1">Available Pages <a class="header-anchor" href="#available-pages" aria-label="Permalink to &quot;Available Pages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>Use it for</th></tr></thead><tbody><tr><td><a href="./installation.html">Installation Planning</a></td><td>Planning Kubernetes, DNS, TLS, identity, registry, and storage prerequisites before installation.</td></tr><tr><td><a href="./user_management.html">User Management</a></td><td>Managing users, workspaces, groups, workspace access, and workspace security policy settings.</td></tr><tr><td><a href="./identity_providers.html">Identity Providers</a></td><td>Connecting external SSO providers to Keycloak and troubleshooting login/group mapping.</td></tr><tr><td><a href="./network_policies.html">Network Policies</a></td><td>Defining reusable egress profiles and assigning outbound network restrictions to workspaces.</td></tr><tr><td><a href="./application_networking.html">Application Networking</a></td><td>Exposing custom applications through prokube gateways and Istio routing.</td></tr><tr><td><a href="./application_authentication.html">Application Authentication</a></td><td>Choosing gateway authentication or direct OIDC for custom applications.</td></tr><tr><td><a href="./storage.html">Storage</a></td><td>Understanding StorageClasses, local storage, replicated storage, and PVC troubleshooting.</td></tr><tr><td><a href="./gpu.html">GPU Administration</a></td><td>Operating GPU nodes, NVIDIA GPU Operator, timeslicing, MIG, and GPU monitoring.</td></tr><tr><td><a href="./backup_restore.html">Backup and Restore</a></td><td>Disaster-recovery scope, backup storage, restore expectations, and validation.</td></tr><tr><td><a href="./upgrading.html">Upgrading</a></td><td>Planning release upgrades, GitOps-driven rollout, and post-upgrade validation.</td></tr><tr><td><a href="./operations_runbooks.html">Operations Runbooks</a></td><td>Administrator runbooks for MinIO, Keycloak bootstrap, and observability operations.</td></tr><tr><td><a href="./../platform/system_status.html">System Status</a></td><td>Checking administrator-only backend component health and backend metadata; the same page also shows workspace pod quota to all users.</td></tr></tbody></table><p>Platform-wide metrics, dashboards, alerts, and log-retention configuration remain administrator/operator topics. Use <a href="./../platform/system_status.html">System Status</a> for quick backend health checks, then use the deployment&#39;s Grafana, Prometheus, Alertmanager, and Loki tools for detailed monitoring.</p>',13)])])}const m=a(n,[["render",i]]);export{h as __pageData,m as default};
